 915 /// One of Op0/Op1 is a constant expression.
 916 /// Attempt to symbolically evaluate the result of a binary operator merging
 917 /// these together.  If target data info is available, it is provided as DL,
 918 /// otherwise DL is null.
 919 Constant *SymbolicallyEvaluateBinop(unsigned Opc, Constant *Op0, Constant *Op1,
 920                                     const DataLayout &DL) {
 921   // SROA
 922 
 923   // Fold (and 0xffffffff00000000, (shl x, 32)) -> shl.
 924   // Fold (lshr (or X, Y), 32) -> (lshr [X/Y], 32) if one doesn't contribute
 925   // bits.
 926 
 927   if (Opc == Instruction::And) {
 928     KnownBits Known0 = computeKnownBits(Op0, DL);
 929     KnownBits Known1 = computeKnownBits(Op1, DL);
 930     if ((Known1.One | Known0.Zero).isAllOnes()) {
 931       // All the bits of Op0 that the 'and' could be masking are already zero.
 932       return Op0;
 933     }
 934     if ((Known0.One | Known1.Zero).isAllOnes()) {
 935       // All the bits of Op1 that the 'and' could be masking are already zero.
 936       return Op1;
 937     }
 938 
 939     Known0 &= Known1;
 940     if (Known0.isConstant())
 941       return ConstantInt::get(Op0->getType(), Known0.getConstant());
 942   }
 943 
 944   // If the constant expr is something like &A[123] - &A[4].f, fold this into a
 945   // constant.  This happens frequently when iterating over a global array.
 946   if (Opc == Instruction::Sub) {
 947     GlobalValue *GV1, *GV2;
 948     APInt Offs1, Offs2;
 949 
 950     if (IsConstantOffsetFromGlobal(Op0, GV1, Offs1, DL))
 951       if (IsConstantOffsetFromGlobal(Op1, GV2, Offs2, DL) && GV1 == GV2) {
 952         unsigned OpSize = DL.getTypeSizeInBits(Op0->getType());
 953 
 954         // (&GV+C1) - (&GV+C2) -> C1-C2, pointer arithmetic cannot overflow.
 955         // PtrToInt may change the bitwidth so we have convert to the right size
 956         // first.
 957         return ConstantInt::get(Op0->getType(), Offs1.zextOrTrunc(OpSize) -
 958                                                 Offs2.zextOrTrunc(OpSize));
 959       }
 960   }
 961 
 962   return nullptr;
 963 }
