3974 static APFloat ConstantFoldAMDGCNCubeIntrinsic(Intrinsic::ID IntrinsicID,
3975                                                const APFloat &S0,
3976                                                const APFloat &S1,
3977                                                const APFloat &S2) {
3978   unsigned ID;
3979   const fltSemantics &Sem = S0.getSemantics();
3980   APFloat MA(Sem), SC(Sem), TC(Sem);
3981   if (abs(S2) >= abs(S0) && abs(S2) >= abs(S1)) {
3982     if (S2.isNegative() && S2.isNonZero() && !S2.isNaN()) {
3983       // S2 < 0
3984       ID = 5;
3985       SC = -S0;
3986     } else {
3987       ID = 4;
3988       SC = S0;
3989     }
3990     MA = S2;
3991     TC = -S1;
3992   } else if (abs(S1) >= abs(S0)) {
3993     if (S1.isNegative() && S1.isNonZero() && !S1.isNaN()) {
3994       // S1 < 0
3995       ID = 3;
3996       TC = -S2;
3997     } else {
3998       ID = 2;
3999       TC = S2;
4000     }
4001     MA = S1;
4002     SC = S0;
4003   } else {
4004     if (S0.isNegative() && S0.isNonZero() && !S0.isNaN()) {
4005       // S0 < 0
4006       ID = 1;
4007       SC = S2;
4008     } else {
4009       ID = 0;
4010       SC = -S2;
4011     }
4012     MA = S0;
4013     TC = -S1;
4014   }
4015   switch (IntrinsicID) {
4016   default:
4017     llvm_unreachable("unhandled amdgcn cube intrinsic");
4018   case Intrinsic::amdgcn_cubeid:
4019     return APFloat(Sem, ID);
4020   case Intrinsic::amdgcn_cubema:
4021     return MA + MA;
4022   case Intrinsic::amdgcn_cubesc:
4023     return SC;
4024   case Intrinsic::amdgcn_cubetc:
4025     return TC;
4026   }
4027 }
