152 /// isLabelChar - Return true for [-a-zA-Z$._0-9].
153 static bool isLabelChar(char C) {
154   return isalnum(static_cast<unsigned char>(C)) || C == '-' || C == '$' ||
155          C == '.' || C == '_';
